import{_ as a,o,c as r,a3 as d}from"./chunks/framework.aYYe0dfI.js";const p=JSON.parse('{"title":"Module generate:dryrun","description":"generate:dryrun 模块负责实现文档生成流程的干运行（dry-run）模式，在不实际调用大语言模型的情况下，模拟生成过程并输出预估请求量和页面摘要。它公开了 build_dry_run_page_summary_texts、build_request_estimate_page、build_llms_page 和 page_summary_cache_key_for_request 等函数，供外层调用以构建干运行页面、计算请求估计和生成缓存键。内部通过 RequestEstimate 结构体分类统计各种请求（如符号分析、模块总结、页面请求等），并依赖 config、extract、generate:analysis 和 generate:model 模块获取配置、提取结果和分析数据。","frontmatter":{"title":"Module generate:dryrun","description":"generate:dryrun 模块负责实现文档生成流程的干运行（dry-run）模式，在不实际调用大语言模型的情况下，模拟生成过程并输出预估请求量和页面摘要。它公开了 build_dry_run_page_summary_texts、build_request_estimate_page、build_llms_page 和 page_summary_cache_key_for_request 等函数，供外层调用以构建干运行页面、计算请求估计和生成缓存键。内部通过 RequestEstimate 结构体分类统计各种请求（如符号分析、模块总结、页面请求等），并依赖 config、extract、generate:analysis 和 generate:model 模块获取配置、提取结果和分析数据。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/generate/dryrun.md","filePath":"zh/clore/modules/generate/dryrun.md"}'),t={name:"zh/clore/modules/generate/dryrun.md"};function c(l,e,s,n,i,u){return o(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="module-generate-dryrun" tabindex="-1">Module <code>generate:dryrun</code> <a class="header-anchor" href="#module-generate-dryrun" aria-label="Permalink to &quot;Module `generate:dryrun`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>generate:dryrun</code> 模块负责实现文档生成流程的干运行（dry-run）模式，在不实际调用大语言模型的情况下，模拟生成过程并输出预估请求量和页面摘要。它公开了 <code>build_dry_run_page_summary_texts</code>、<code>build_request_estimate_page</code>、<code>build_llms_page</code> 和 <code>page_summary_cache_key_for_request</code> 等函数，供外层调用以构建干运行页面、计算请求估计和生成缓存键。内部通过 <code>RequestEstimate</code> 结构体分类统计各种请求（如符号分析、模块总结、页面请求等），并依赖 <code>config</code>、<code>extract</code>、<code>generate:analysis</code> 和 <code>generate:model</code> 模块获取配置、提取结果和分析数据。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../config/"><code>config</code></a></li><li><a href="./../extract/"><code>extract</code></a></li><li><a href="./analysis"><code>generate:analysis</code></a></li><li><a href="./model"><code>generate:model</code></a></li><li><code>std</code></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./scheduler"><code>generate:scheduler</code></a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-generate-build-dry-run-page-summary-texts" tabindex="-1"><code>clore::generate::build_dry_run_page_summary_texts</code> <a class="header-anchor" href="#clore-generate-build-dry-run-page-summary-texts" aria-label="Permalink to &quot;`clore::generate::build_dry_run_page_summary_texts`&quot;">​</a></h3><p>Declaration: <code>generate/dryrun.cppm:11</code></p><p>Definition: <code>generate/dryrun.cppm:316</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>函数 <code>clore::generate::build_dry_run_page_summary_texts</code> 遍历输入的 <code>prompt_requests</code> 向量，为每个 <code>request</code> 生成干运行的页面摘要文本。其核心算法基于三个依赖函数的协作：首先通过 <code>page_summary_cache_key_for_request</code> 判断当前请求是否需要摘要，若无缓存键则跳过；接着调用 <code>fallback_page_summary_for_request</code> 获取降级摘要，若结果为空则继续；最后以 <code>prompt_request_key</code> 生成的字符串为键，将非空摘要插入结果映射。整个流程依赖 <code>PagePlan</code> 对象 <code>plan</code> 提供的上下文，并通过条件跳过无意义请求来避免无效计算，最终返回一个按键（即请求标识）索引的摘要集合。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>plan</code></li><li><code>prompt_requests</code></li><li><code>page_summary_cache_key_for_request</code></li><li><code>fallback_page_summary_for_request</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used in dry run page generation to collect summary texts for each prompt request.</li><li>Likely called by <code>generate_dry_run</code> or related functions.</li></ul><h3 id="clore-generate-build-llms-page" tabindex="-1"><code>clore::generate::build_llms_page</code> <a class="header-anchor" href="#clore-generate-build-llms-page" aria-label="Permalink to &quot;`clore::generate::build_llms_page`&quot;">​</a></h3><p>Declaration: <code>generate/dryrun.cppm:19</code></p><p>Definition: <code>generate/dryrun.cppm:333</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>实现摘要：<code>clore::generate::build_llms_page</code> 负责构造一个 Markdown 格式的索引页面，输出为 <code>llms.txt</code>。它首先通过 <code>project_name_from_config</code> 提取项目名称，并预分配内容缓冲区。随后依次附加项目标题行、描述性说明以及指向 API 参考页面 (<code>index.md</code>) 的链接；若 <code>request_estimate_path</code> 非空，则附加指向 Dry Run 请求估算页面的链接。核心流程是三次调用 <code>append_llms_section</code>，分别绑定 <code>PageType::Module</code>、<code>PageType::Namespace</code> 和 <code>PageType::File</code>，将 <code>plan_set</code> 中的对应章节按标签（模块、命名空间、文件）追加到内容末尾。最终返回包含标题、固定相对路径 <code>&quot;llms.txt&quot;</code> 和构建好的 <code>content</code> 的 <code>GeneratedPage</code> 对象。该函数依赖 <code>project_name_from_config</code> 与 <code>append_llms_section</code> 两个辅助函数完成配置读取和分节生成。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>config::TaskConfig</code> <code>config</code> (via <code>project_name_from_config</code>)</li><li><code>PagePlanSet</code> <code>plan_set</code></li><li><code>std::string_view</code> <code>request_estimate_path</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>returned <code>GeneratedPage</code> object (fields <code>title</code>, <code>relative_path</code>, <code>content</code>)</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called during documentation generation to produce the <code>llms.txt</code> index page</li></ul><h3 id="clore-generate-build-request-estimate-page" tabindex="-1"><code>clore::generate::build_request_estimate_page</code> <a class="header-anchor" href="#clore-generate-build-request-estimate-page" aria-label="Permalink to &quot;`clore::generate::build_request_estimate_page`&quot;">​</a></h3><p>Declaration: <code>generate/dryrun.cppm:15</code></p><p>Definition: <code>generate/dryrun.cppm:230</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>该函数主要将来自 <code>clore::generate::(anonymous namespace)::estimate_request_count</code> 的统计结果与 <code>clore::generate::(anonymous namespace)::project_name_from_config</code> 提供的项目名称组合起来，组装成一个完整的 <code>GeneratedPage</code>。内部流程是：先为给定的 <code>plan_set</code> 和 <code>model</code> 计算 <code>RequestEstimate</code>，然后通过字符串拼接和 <code>std::format</code> 构建一个固定布局的 Markdown 内容，其中包括 YAML 元数据、项目名称、总计统计、页面任务和符号任务的详细分项，最后将内容包裹在 <code>GeneratedPage</code> 中并设置路径为 <code>&quot;request-estimate.md&quot;</code>。</p><p>该函数不涉及任何分支或循环，完全是一条顺序执行的格式化流水线。它的核心依赖是 <code>RequestEstimate</code> 结构（提供 <code>total_requests</code>、<code>page_requests</code>、<code>symbol_requests</code> 等计数器）以及 <code>project_name_from_config</code> 的返回值。生成的页面专门用于 dry‑run 模式，不触发任何模型调用，仅报告当前计划排期的预期提示任务数量。</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameters <code>plan_set</code>, <code>model</code>, <code>config</code></li><li>callees <code>estimate_request_count</code>, <code>project_name_from_config</code></li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>local variable <code>content</code></li><li>returned <code>GeneratedPage</code>&#39;s fields</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called during dry-run generation</li><li>builds page for estimating prompt task load</li></ul><h3 id="clore-generate-page-summary-cache-key-for-request" tabindex="-1"><code>clore::generate::page_summary_cache_key_for_request</code> <a class="header-anchor" href="#clore-generate-page-summary-cache-key-for-request" aria-label="Permalink to &quot;`clore::generate::page_summary_cache_key_for_request`&quot;">​</a></h3><p>Declaration: <code>generate/dryrun.cppm:23</code></p><p>Definition: <code>generate/dryrun.cppm:293</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>该函数通过一个 switch 语句检查 <code>request.kind</code> 的枚举值。当 <code>request.kind</code> 为 <code>PromptKind::NamespaceSummary</code> 或 <code>PromptKind::ModuleSummary</code> 时，若 <code>plan.owner_keys</code> 非空，则返回 <code>plan.owner_keys.front()</code> 作为可选的缓存键；否则返回 <code>std::nullopt</code>。此逻辑依赖于 <code>PagePlan</code> 类型的 <code>owner_keys</code> 字段，该字段在调用上下文中由调用方（如 <code>build_request_estimate_page</code>）提供。</p><p>对于其他所有 <code>PromptKind</code> 枚举值（包括 <code>ModuleArchitecture</code>、<code>IndexOverview</code>、<code>FunctionAnalysis</code>、<code>TypeAnalysis</code>、<code>VariableAnalysis</code> 以及所有声明/实现摘要种类），该函数直接返回 <code>std::nullopt</code>，表示对应请求不参与页面摘要缓存。Switch 末尾的 <code>return std::nullopt</code> 确保了所有分支均被覆盖，但实际执行中不会到达该处。</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>plan.owner_keys</code></li><li><code>request.kind</code></li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to produce a cache key for page summary caching</li><li>Filters requests that should be cached based on prompt kind</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>模块 <code>generate:dryrun</code> 是文档生成管线中干运行（dry-run）阶段的核心，负责在无需实际调用大模型的情况下估算请求量并构建预览页面。它通过内部匿名命名空间分解了多个职责：<code>RequestEstimate</code> 结构聚合了各类分析请求（符号提取、函数/类型/变量分析、模块摘要等）的计数，<code>estimate_request_count</code> 利用来自 <code>generate:model</code> 的<code>plan_set</code> 计算这些估计值；<code>append_llms_section</code> 借助 <code>LabeledPage</code> 辅助结构生成面向 LLM 的页面片段。模块从 <code>config</code> 获取项目配置，从 <code>extract</code> 获取符号数据，并依赖 <code>generate:analysis</code> 的分析结果，形成清晰的导入层次。公开的函数如 <code>build_dry_run_page_summary_texts</code>、<code>build_request_estimate_page</code>、<code>build_llms_page</code> 和 <code>page_summary_cache_key_for_request</code> 提供了干运行场景下摘要文本生成、请求估计、LLMS 页面构建及缓存键生成等接口，使得调用者可以独立演练生成流程而无需依赖外部模型。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../config/">Module config</a></li><li><a href="./../extract/">Module extract</a></li><li><a href="./analysis">Module generate:analysis</a></li><li><a href="./model">Module generate:model</a></li></ul>',62)])])}const _=a(t,[["render",c]]);export{p as __pageData,_ as default};
